    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "PERP_BTC_USDT",
        //         "clientOrderId": 0,
        //         "orderId": 52952826,
        //         "type": "LIMIT",
        //         "side": "SELL",
        //         "quantity": 0.01,
        //         "price": 22000,
        //         "tradeId": 0,
        //         "executedPrice": 0,
        //         "executedQuantity": 0,
        //         "fee": 0,
        //         "feeAsset": "USDT",
        //         "totalExecutedQuantity": 0,
        //         "status": "NEW",
        //         "reason": '',
        //         "orderTag": "default",
        //         "totalFee": 0,
        //         "visible": 0.01,
        //         "timestamp": 1657515556798,
        //         "reduceOnly": false,
        //         "maker": false
        //     }
        // algo order
        //     {
        //         "symbol":"PERP_MATIC_USDC",
        //         "rootAlgoOrderId":123,
        //         "parentAlgoOrderId":123,
        //         "algoOrderId":123,
        //         "orderTag":"some tags",
        //         "algoType": "STOP",
        //         "clientOrderId":"client_id",
        //         "type":"LIMIT",
        //         "side":"BUY",
        //         "quantity":7029.0,
        //         "price":0.7699,
        //         "tradeId":0,
        //         "triggerTradePrice":0,
        //         "triggerTime":1234567,
        //         "triggered": false,
        //         "activated": false,
        //         "executedPrice":0.0,
        //         "executedQuantity":0.0,
        //         "fee":0.0,
        //         "feeAsset":"USDC",
        //         "totalExecutedQuantity":0.0,
        //         "averageExecutedQuantity":0.0,
        //         "avgPrice":0,
        //         "triggerPrice":0.0,
        //         "triggerPriceType":"STOP",
        //         "isActivated": false,
        //         "status":"NEW",
        //         "rootAlgoStatus": "FILLED",
        //         "algoStatus": "FILLED",
        //         "reason":"",
        //         "totalFee":0.0,
        //         "visible": 7029.0,
        //         "visibleQuantity":7029.0,
        //         "timestamp":1704679472448,
        //         "maker":false,
        //         "isMaker":false,
        //         "createdTime":1704679472448
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object orderId = this.safeString(order, "orderId");
        Object marketId = this.safeString(order, "symbol");
        market = this.market(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object timestamp = this.safeInteger(order, "timestamp");
        Object fee = new java.util.HashMap<String, Object>() {{
            put( "cost", WoofiproCore.this.safeString(order, "totalFee") );
            put( "currency", WoofiproCore.this.safeString(order, "feeAsset") );
        }};
        Object priceString = this.safeString(order, "price");
        Object price = this.safeNumber(order, "price");
        Object avgPrice = this.safeNumber(order, "avgPrice");
        if (Helpers.isTrue(Helpers.isTrue(Precise.stringEq(priceString, "0")) && Helpers.isTrue((!Helpers.isEqual(avgPrice, null)))))
        {
            price = avgPrice;
        }
        Object amount = this.safeString(order, "quantity");
        Object side = this.safeStringLower(order, "side");
        Object type = this.safeStringLower(order, "type");
        Object filled = this.safeNumber(order, "totalExecutedQuantity");
        Object totalExecQuantity = this.safeString(order, "totalExecutedQuantity");
        Object remaining = amount;
        if (Helpers.isTrue(Precise.stringGe(amount, totalExecQuantity)))
        {
            remaining = Precise.stringSub(remaining, totalExecQuantity);
        }
        Object rawStatus = this.safeString(order, "status");
        Object status = this.parseOrderStatus(rawStatus);
        Object trades = null;
        Object clientOrderId = this.safeString(order, "clientOrderId");
        Object triggerPrice = this.safeNumber(order, "triggerPrice");
        final Object finalPrice = price;
        final Object finalRemaining = remaining;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", symbol );
            put( "id", orderId );
            put( "clientOrderId", clientOrderId );
            put( "timestamp", timestamp );
            put( "datetime", WoofiproCore.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", timestamp );
            put( "type", type );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", side );
            put( "price", finalPrice );
            put( "stopPrice", triggerPrice );
            put( "triggerPrice", triggerPrice );
            put( "amount", amount );
            put( "cost", null );
            put( "average", null );
            put( "filled", filled );
            put( "remaining", finalRemaining );
            put( "status", status );
            put( "fee", fee );
            put( "trades", trades );
        }});
    }

    public void handleOrderUpdate(Client client, Object message)
    {
        //
        //     {
        //         "topic": "executionreport",
        //         "ts": 1657515556799,
        //         "data": {
        //             "symbol": "PERP_BTC_USDT",
        //             "clientOrderId": 0,
        //             "orderId": 52952826,
        //             "type": "LIMIT",
        //             "side": "SELL",
        //             "quantity": 0.01,
        //             "price": 22000,
        //             "tradeId": 0,
        //             "executedPrice": 0,
        //             "executedQuantity": 0,
        //             "fee": 0,
        //             "feeAsset": "USDT",
        //             "totalExecutedQuantity": 0,
        //             "status": "NEW",
        //             "reason": '',
        //             "orderTag": "default",
        //             "totalFee": 0,
        //             "visible": 0.01,
        //             "timestamp": 1657515556799,
        //             "maker": false
        //         }
        //     }
        //
        Object topic = this.safeString(message, "topic");
        Object data = this.safeValue(message, "data");
        if (Helpers.isTrue(Helpers.isArray(data)))
        {
            // algoexecutionreport
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(data)); i++)
            {
                Object order = Helpers.GetValue(data, i);
                Object tradeId = this.omitZero(this.safeString(data, "tradeId"));
                if (Helpers.isTrue(!Helpers.isEqual(tradeId, null)))
                {
                    this.handleMyTrade(client, order);
                }
                this.handleOrder(client, order, topic);
            }
        } else
        {
            // executionreport
            Object tradeId = this.omitZero(this.safeString(data, "tradeId"));
            if (Helpers.isTrue(!Helpers.isEqual(tradeId, null)))
            {
                this.handleMyTrade(client, data);
            }
            this.handleOrder(client, data, topic);
        }
    }

    public void handleOrder(Client client, Object message, Object topic)
    {
        Object parsed = this.parseWsOrder(message);
        Object symbol = this.safeString(parsed, "symbol");
        Object orderId = this.safeString(parsed, "id");
        if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
        {
            if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
            {
                Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
                this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            }
            Object cachedOrders = this.orders;
            Object orders = this.safeDict(((io.github.ccxt.ws.ArrayCache)cachedOrders).hashmap, symbol, new java.util.HashMap<String, Object>() {{}});
            Object order = this.safeDict(orders, orderId);
            if (Helpers.isTrue(!Helpers.isEqual(order, null)))
            {
                Object fee = this.safeValue(order, "fee");
                if (Helpers.isTrue(!Helpers.isEqual(fee, null)))
                {
                    Helpers.addElementToObject(parsed, "fee", fee);
                }
                Object fees = this.safeList(order, "fees");
                if (Helpers.isTrue(!Helpers.isEqual(fees, null)))
                {
                    Helpers.addElementToObject(parsed, "fees", fees);
                }
                Helpers.addElementToObject(parsed, "trades", this.safeList(order, "trades"));
                Helpers.addElementToObject(parsed, "timestamp", this.safeInteger(order, "timestamp"));
                Helpers.addElementToObject(parsed, "datetime", this.safeString(order, "datetime"));
            }
            Helpers.callDynamically(cachedOrders, "append", new Object[]{parsed});
            client.resolve(this.orders, topic);
            Object messageHashSymbol = Helpers.add(Helpers.add(topic, ":"), symbol);
            client.resolve(this.orders, messageHashSymbol);
        }
    }

    public void handleMyTrade(Client client, Object message)
    {
        //
        // {
        //     symbol: 'PERP_XRP_USDC',
        //     clientOrderId: '',
        //     orderId: 1167632251,
        //     type: 'MARKET',
        //     side: 'BUY',
        //     quantity: 20,
        //     price: 0,
        //     tradeId: '1715179456664012',
        //     executedPrice: 0.5276,
        //     executedQuantity: 20,
        //     fee: 0.006332,
        //     feeAsset: 'USDC',
        //     totalExecutedQuantity: 20,
        //     avgPrice: 0.5276,
        //     averageExecutedPrice: 0.5276,
        //     status: 'FILLED',
        //     reason: '',
        //     totalFee: 0.006332,
        //     visible: 0,
        //     visibleQuantity: 0,
        //     timestamp: 1715179456660,
        //     orderTag: 'CCXT',
        //     createdTime: 1715179456656,
        //     maker: false
        // }
        //
        Object messageHash = "myTrades";
        Object marketId = this.safeString(message, "symbol");
        Object market = this.safeMarket(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object trade = this.parseWsTrade(message, market);
        Object trades = this.myTrades;
        if (Helpers.isTrue(Helpers.isEqual(trades, null)))
        {
            Object limit = this.safeInteger(this.options, "tradesLimit", 1000);
            trades = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            this.myTrades = trades;
        }
        Helpers.callDynamically(trades, "append", new Object[]{trade});
        client.resolve(trades, messageHash);
        Object symbolSpecificMessageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
        client.resolve(trades, symbolSpecificMessageHash);
    }

    /**
     * @method
     * @name woofipro#watchPositions
     * @see https://orderly.network/docs/build-on-omnichain/evm-api/websocket-api/private/position-push
     * @description watch all open positions
     * @param {string[]} [symbols] list of unified market symbols
     * @param {int} [since] timestamp in ms of the earliest position to fetch
     * @param {int} [limit] the maximum number of positions to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} a list of [position structure]{@link https://docs.ccxt.com/en/latest/manual.html#position-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchPositions(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbols = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object messageHashes = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            symbols = this.marketSymbols(symbols);
            if (!Helpers.isTrue(this.isEmpty(symbols)))
            {
                for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(symbols)); i++)
                {
                    Object symbol = Helpers.GetValue(symbols, i);
                    ((java.util.List<Object>)messageHashes).add(Helpers.add("positions::", symbol));
                }
            } else
            {
                ((java.util.List<Object>)messageHashes).add("positions");
            }
            Object url = Helpers.add(Helpers.add(Helpers.GetValue(Helpers.GetValue(Helpers.GetValue(this.urls, "api"), "ws"), "private"), "/"), this.accountId);
            Client client = this.client(url);
            this.setPositionsCache(client, symbols);
            Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", true);
            Object awaitPositionsSnapshot = this.handleOption("watchPositions", "awaitPositionsSnapshot", true);
            if (Helpers.isTrue(Helpers.isTrue(Helpers.isTrue(fetchPositionsSnapshot) && Helpers.isTrue(awaitPositionsSnapshot)) && Helpers.isTrue(Helpers.isEqual(this.positions, null))))
            {
                Object snapshot = client.future("fetchPositionsSnapshot").getFuture().join();
                return this.filterBySymbolsSinceLimit(snapshot, symbols, since, limit, true);
            }
            Object request = new java.util.HashMap<String, Object>() {{
                put( "event", "subscribe" );
                put( "topic", "position" );
            }};
            Object newPositions = (this.watchPrivateMultiple(messageHashes, request, parameters)).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                return newPositions;
            }
            return this.filterBySymbolsSinceLimit(this.positions, symbols, since, limit, true);
        });

    }

    public void setPositionsCache(Client client, Object type, Object... optionalArgs)
    {
        Object symbols = Helpers.getArg(optionalArgs, 0, null);
        Object fetchPositionsSnapshot = this.handleOption("watchPositions", "fetchPositionsSnapshot", false);
        if (Helpers.isTrue(fetchPositionsSnapshot))
        {
            Object messageHash = "fetchPositionsSnapshot";
            if (!Helpers.isTrue((Helpers.inOp(client.futures, messageHash))))
            {
                client.future((String)messageHash);
                this.spawn(() -> { try { this.loadPositionsSnapshot(client, messageHash); } catch(Exception _e) { throw new RuntimeException(_e); } });
            }
        } else
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
    }

    public java.util.concurrent.CompletableFuture<Object> loadPositionsSnapshot(Client client, Object messageHash2)
    {
        final Object messageHash3 = messageHash2;
        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {
            Object messageHash = messageHash3;
            Object positions = (this.fetchPositionsAsync()).join();
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
            Object cache = this.positions;
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(positions)); i++)
            {
                Object position = Helpers.GetValue(positions, i);
                Object contracts = this.safeString(position, "contracts", "0");
                if (Helpers.isTrue(Precise.stringGt(contracts, "0")))
                {
                    Helpers.callDynamically(cache, "append", new Object[]{position});
                }
            }
            // don't remove the future from the .futures cache
            if (Helpers.isTrue(Helpers.inOp(client.futures, messageHash)))
            {
                io.github.ccxt.ws.Future future = (io.github.ccxt.ws.Future)Helpers.GetValue(client.futures, messageHash);
                ((io.github.ccxt.ws.Future)future).resolve(cache);
                client.resolve(cache, "positions");
            }
            return null;
        });

    }

    public void handlePositions(Client client, Object message)
    {
        //
        //    {
        //        "topic":"position",
        //        "ts":1705292345255,
        //        "data":{
        //           "positions":[
        //              {
        //                     "symbol":"PERP_ETH_USDC",
        //                     "positionQty":3.1408,
        //                     "costPosition":5706.51952,
        //                     "lastSumUnitaryFunding":0.804,
        //                     "sumUnitaryFundingVersion":0,
        //                     "pendingLongQty":0.0,
        //                     "pendingShortQty":-1.0,
        //                     "settlePrice":1816.9,
        //                     "averageOpenPrice":1804.51490427,
        //                     "unsettledPnl":-2.79856,
        //                     "pnl24H":-338.90179488,
        //                     "fee24H":4.242423,
        //                     "markPrice":1816.2,
        //                     "estLiqPrice":0.0,
        //                     "version":179967,
        //                     "imrwithOrders":0.1,
        //                     "mmrwithOrders":0.05,
        //                     "mmr":0.05,
        //                     "imr":0.1,
        //                     "timestamp":1685154032762
        //              }
        //           ]
        //        }
        //    }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object rawPositions = this.safeList(data, "positions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        if (Helpers.isTrue(Helpers.isEqual(this.positions, null)))
        {
            this.positions = new ArrayCache.ArrayCacheBySymbolBySide();
        }
        Object cache = this.positions;
        Object newPositions = new java.util.ArrayList<Object>(java.util.Arrays.asList());
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(rawPositions)); i++)
        {
            Object rawPosition = Helpers.GetValue(rawPositions, i);
            Object marketId = this.safeString(rawPosition, "symbol");
            Object market = this.safeMarket(marketId);
            Object position = this.parseWsPosition(rawPosition, market);
            ((java.util.List<Object>)newPositions).add(position);
            Helpers.callDynamically(cache, "append", new Object[]{position});
            Object messageHash = Helpers.add("positions::", Helpers.GetValue(market, "symbol"));
            client.resolve(position, messageHash);
        }
        client.resolve(newPositions, "positions");
    }

    public Object parseWsPosition(Object position, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol":"PERP_ETH_USDC",
        //         "positionQty":3.1408,
        //         "costPosition":5706.51952,
        //         "lastSumUnitaryFunding":0.804,
        //         "sumUnitaryFundingVersion":0,
        //         "pendingLongQty":0.0,
        //         "pendingShortQty":-1.0,
        //         "settlePrice":1816.9,
        //         "averageOpenPrice":1804.51490427,
        //         "unsettledPnl":-2.79856,
        //         "pnl24H":-338.90179488,
        //         "fee24H":4.242423,
        //         "markPrice":1816.2,
        //         "estLiqPrice":0.0,
        //         "version":179967,
        //         "imrwithOrders":0.1,
        //         "mmrwithOrders":0.05,
        //         "mmr":0.05,
        //         "imr":0.1,
        //         "timestamp":1685154032762
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object contract = this.safeString(position, "symbol");
        market = this.safeMarket(contract, market);
        Object size = this.safeString(position, "positionQty");
        Object side = null;
        if (Helpers.isTrue(Precise.stringGt(size, "0")))
        {
            side = "long";
        } else
        {
            side = "short";
        }
        Object contractSize = this.safeString(market, "contractSize");
        Object markPrice = this.safeString(position, "markPrice");
        Object timestamp = this.safeInteger(position, "timestamp");
        Object entryPrice = this.safeString(position, "averageOpenPrice");
        Object unrealisedPnl = this.safeString(position, "unsettledPnl");
        size = Precise.stringAbs(size);
        Object notional = Precise.stringMul(size, markPrice);
        final Object finalMarket = market;
        final Object finalSize = size;
        final Object finalSide = side;
        return this.safePosition(new java.util.HashMap<String, Object>() {{
            put( "info", position );
            put( "id", null );
            put( "symbol", WoofiproCore.this.safeString(finalMarket, "symbol") );
            put( "timestamp", timestamp );
            put( "datetime", WoofiproCore.this.iso8601(timestamp) );
            put( "lastUpdateTimestamp", null );
            put( "initialMargin", null );
            put( "initialMarginPercentage", null );
            put( "maintenanceMargin", null );
            put( "maintenanceMarginPercentage", null );
            put( "entryPrice", WoofiproCore.this.parseNumber(entryPrice) );
            put( "notional", WoofiproCore.this.parseNumber(notional) );
            put( "leverage", null );
            put( "unrealizedPnl", WoofiproCore.this.parseNumber(unrealisedPnl) );
            put( "contracts", WoofiproCore.this.parseNumber(finalSize) );
            put( "contractSize", WoofiproCore.this.parseNumber(contractSize) );
            put( "marginRatio", null );
            put( "liquidationPrice", WoofiproCore.this.safeNumber(position, "estLiqPrice") );
            put( "markPrice", WoofiproCore.this.parseNumber(markPrice) );
            put( "lastPrice", null );
            put( "collateral", null );
            put( "marginMode", "cross" );
            put( "marginType", null );
            put( "side", finalSide );
            put( "percentage", null );
            put( "hedged", null );
            put( "stopLossPrice", null );
            put( "takeProfitPrice", null );
        }});
    }

    /**
     * @method
     * @name woofipro#watchBalance
     * @description watch balance and get the amount of funds available for trading or funds locked in orders
     * @see https://orderly.network/docs/build-on-omnichain/evm-api/websocket-api/private/balance
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} a [balance structure]{@link https://docs.ccxt.com/?id=balance-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchBalance(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object topic = "balance";
            Object messageHash = topic;
            Object request = new java.util.HashMap<String, Object>() {{
                put( "event", "subscribe" );
                put( "topic", topic );
            }};
            Object message = this.extend(request, parameters);
            return (this.watchPrivate(messageHash, message)).join();
        });

    }

    public void handleBalance(Client client, Object message)
    {
        //
        //     {
        //         "topic":"balance",
        //         "ts":1651836695254,
        //         "data":{
        //             "balances":{
        //                 "USDC":{
        //                     "holding":5555815.47398272,
        //                     "frozen":0,
        //                     "interest":0,
        //                     "pendingShortQty":0,
        //                     "pendingExposure":0,
        //                     "pendingLongQty":0,
        //                     "pendingLongExposure":0,
        //                     "version":894,
        //                     "staked":51370692,
        //                     "unbonding":0,
        //                     "vault":0,
        //                     "averageOpenPrice":0.00000574,
        //                     "pnl24H":0,
        //                     "fee24H":0.01914,
        //                     "markPrice":0.31885
        //                 }
        //             }
        //         }
        //     }
        //
        Object data = this.safeDict(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object balances = this.safeDict(data, "balances", new java.util.HashMap<String, Object>() {{}});
        Object keys = Helpers.objectKeys(balances);
        Object ts = this.safeInteger(message, "ts");
        Helpers.addElementToObject(this.balance, "info", data);
        Helpers.addElementToObject(this.balance, "timestamp", ts);
        Helpers.addElementToObject(this.balance, "datetime", this.iso8601(ts));
        for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(keys)); i++)
        {
            Object key = Helpers.GetValue(keys, i);
            Object value = Helpers.GetValue(balances, key);
            Object code = this.safeCurrencyCode(key);
            Object account = ((Helpers.isTrue((Helpers.inOp(this.balance, code))))) ? Helpers.GetValue(this.balance, code) : this.account();
            Object total = this.safeString(value, "holding");
            Object used = this.safeString(value, "frozen");
            Helpers.addElementToObject(account, "total", total);
            Helpers.addElementToObject(account, "used", used);
            Helpers.addElementToObject(account, "free", Precise.stringSub(total, used));
            Helpers.addElementToObject(this.balance, code, account);
        }
        this.balance = this.safeBalance(this.balance);
        client.resolve(this.balance, "balance");
    }

    public Object handleErrorMessage(Client client, Object message)
    {
        //
        // {"id":"1","event":"subscribe","success":false,"ts":1710780997216,"errorMsg":"Auth is needed."}
        //
        if (!Helpers.isTrue((Helpers.inOp(message, "success"))))
        {
            return false;
        }
        Object success = this.safeBool(message, "success");
        if (Helpers.isTrue(success))
        {
            return false;
        }
        Object errorMessage = this.safeString(message, "errorMsg");
        try
        {
            if (Helpers.isTrue(!Helpers.isEqual(errorMessage, null)))
            {
                Object feedback = Helpers.add(Helpers.add(this.id, " "), this.json(message));
                this.throwExactlyMatchedException(Helpers.GetValue(this.exceptions, "exact"), errorMessage, feedback);
            }
            return false;
        } catch(Exception error)
        {
            if (Helpers.isTrue(Helpers.isInstance(error, AuthenticationError.class)))
            {
                Object messageHash = "authenticated";
                client.reject(error, messageHash);
                if (Helpers.isTrue(Helpers.inOp(client.subscriptions, messageHash)))
                {
                    ((java.util.Map<String,Object>)client.subscriptions).remove((String)messageHash);
                }
            } else
            {
                client.reject(error);
            }
            return true;
        }
    }

    public void handleMessage(Client client, Object message)
    {
        if (Helpers.isTrue(this.handleErrorMessage(client, message)))
        {
            return;
        }
        Object methods = new java.util.HashMap<String, Object>() {{
            put( "ping", "handlePing");
            put( "pong", "handlePong");
            put( "subscribe", "handleSubscribe");
            put( "orderbook", "handleOrderBook");
            put( "ticker", "handleTicker");
            put( "tickers", "handleTickers");
            put( "kline", "handleOHLCV");
            put( "trade", "handleTrade");
            put( "auth", "handleAuth");
            put( "executionreport", "handleOrderUpdate");
            put( "algoexecutionreport", "handleOrderUpdate");
            put( "position", "handlePositions");
            put( "balance", "handleBalance");
            put( "bbos", "handleBidAsk");
        }};
        Object eventVar = this.safeString(message, "event");
        Object method = this.safeValue(methods, eventVar);
        if (Helpers.isTrue(!Helpers.isEqual(method, null)))
        {
            Helpers.callDynamically(this, method, new Object[] {client, message});
            return;
        }
        Object topic = this.safeString(message, "topic");
        if (Helpers.isTrue(!Helpers.isEqual(topic, null)))
        {
            method = this.safeValue(methods, topic);
            if (Helpers.isTrue(!Helpers.isEqual(method, null)))
            {
                Helpers.callDynamically(this, method, new Object[] {client, message});
                return;
            }
            Object splitTopic = Helpers.split(topic, "@");
            Object splitLength = Helpers.getArrayLength(splitTopic);
            if (Helpers.isTrue(Helpers.isEqual(splitLength, 2)))
            {
                Object name = this.safeString(splitTopic, 1);
                method = this.safeValue(methods, name);
                if (Helpers.isTrue(!Helpers.isEqual(method, null)))
                {
                    Helpers.callDynamically(this, method, new Object[] {client, message});
                    return;
                }
                Object splitName = Helpers.split(name, "_");
                Object splitNameLength = Helpers.getArrayLength(splitTopic);
                if (Helpers.isTrue(Helpers.isEqual(splitNameLength, 2)))
                {
                    method = this.safeValue(methods, this.safeString(splitName, 0));
                    if (Helpers.isTrue(!Helpers.isEqual(method, null)))
                    {
                        Helpers.callDynamically(this, method, new Object[] {client, message});
                    }
                }
            }
        }
    }

